#!/usr/bin/env python3\n\"\"\"\nTest Real Market Data Collection\n\"\"\"\n\nfrom real_market_data_collector import RealMarketDataCollector\nimport logging\n\n# Setup logging\nlogging.basicConfig(level=logging.INFO)\n\ndef test_data_collection():\n    print(\"🚀 Testing Real Market Data Collection\")\n    print(\"=\" * 50)\n    \n    try:\n        # Initialize collector\n        collector = RealMarketDataCollector()\n        print(\"✅ Collector initialized successfully\")\n        \n        # Test with BTC 1h data\n        print(\"\\n📊 Testing BTC data collection...\")\n        df = collector.collect_historical_data('BTCUSDT', '1h', 7)\n        print(f\"📈 Collected {len(df)} records\")\n        \n        if not df.empty:\n            # Store to database\n            collector.store_data_to_db(df)\n            print(\"💾 Data stored to database\")\n            \n            # Verify stored data\n            sample = collector.get_training_data('1h', 10)\n            print(f\"📋 Retrieved {len(sample)} sample records\")\n            \n            if not sample.empty:\n                latest_price = sample['close'].iloc[-1]\n                print(f\"💰 Latest BTC price: ${latest_price:.2f}\")\n                print(f\"📅 Date range: {sample['timestamp'].min()} to {sample['timestamp'].max()}\")\n                print(\"\\n🎉 SUCCESS! Real market data collection working!\")\n                \n                # Save sample\n                sample.to_csv('training_data/test_sample.csv', index=False)\n                print(\"💾 Sample saved to training_data/test_sample.csv\")\n                \n                return True\n            else:\n                print(\"❌ No sample data retrieved\")\n                return False\n        else:\n            print(\"❌ No data collected\")\n            return False\n            \n    except Exception as e:\n        print(f\"❌ Error: {e}\")\n        return False\n\nif __name__ == \"__main__\":\n    success = test_data_collection()\n    if success:\n        print(\"\\n🔥 Ready to collect comprehensive dataset!\")\n        print(\"Run: python real_market_data_collector.py\")\n    else:\n        print(\"\\n⚠️ Check your API configuration\") 